def max_steps(board):
    n, m = len(board), len(board[0])
    directions = {'L': (0, -1), 'R': (0, 1), 'U': (-1, 0), 'D': (1, 0)}
    visited = [[False]*m for _ in range(n)]
    max_step = 0
    max_start = (0, 0)

    for i in range(n):
        for j in range(m):
            if visited[i][j]:
                continue
            stack = [(i, j, 0)]
            visited[i][j] = True
            step = 0
            while stack:
                x, y, s = stack.pop()
                step = max(step, s)
                dx, dy = directions[board[x][y]]
                nx, ny = x + dx, y + dy
                if 0 <= nx < n and 0 <= ny < m and not visited[nx][ny]:
                    stack.append((nx, ny, s+1))
                    visited[nx][ny] = True
                else:
                    stack.append((x, y, s+1))
            if step > max_step:
                max_step = step
                max_start = (i+1, j+1)
            for x in range(n):
                for y in range(m):
                    visited[x][y] = False
    return (*max_start, max_step)

