        if len(word) <= len(language_dict[word]):
            recorded_lecture.append(word)
        else:
            recorded_lecture.append(language_dict[word])

    return recorded_lecture


def main():
    n, m = map(int, input().split())
    word_pairs = [input().split() for _ in range(m)]
    lecture = input().split()

    recorded_lecture = record_lecture(n, m, word_pairs, lecture)
    print(*recorded_lecture)


